sql:
SELECT AVG(total_hospital_beds_mean) AS average_total_hospital_beds_mean
FROM forecast_data
WHERE forecast_date LIKE '2020%';

SELECT total_hospital_beds_max
FROM forecast_data
WHERE intervention = 'Best case';

SELECT seasonality, AVG(total_hospital_beds_mean) AS average_total_hospital_beds
FROM forecast_data
GROUP BY seasonality;

external_knowledge:
- 'forecast_accuracy' refers to the certainty or confidence in the forecast;
- 'Worst case' metaphorically represents the 'darkest clouds'; 
- 'New York City' remains as the location entity;
- '2020-09-01' to '2020-12-31' represents the final quarter of the year 2020;
- 'forecast_data', 'locations', and 'interventions' are the three tables connected to provide the necessary information.

sql:
SELECT fd.forecast_accuracy, i.intervention_name
FROM forecast_data fd
INNER JOIN interventions i ON fd.intervention = i.intervention_id;

SELECT forecast_id, forecast_accuracy
FROM forecast_data
ORDER BY forecast_accuracy DESC;

SELECT forecast_accuracy
FROM forecast_data
ORDER BY forecast_accuracy DESC;
